  hasNativeGoBack?: boolean;
  nativeGoBackFn?: () => void;
  hasHeader?: boolean;
  headerTitle?: string;
  isLoading?: boolean;
  testID?: string;
  throttle?: number;
  showValue?: boolean;
  setShowValue?: (e: boolean) => void;
  rightSecondaryIcon?: PropsIcon['name'];
